// ── Multi-Provider LLM Call ────────────────────────────────────────────
// Reads LLM_PROVIDER from env: claude | openai | gemini
// Falls back gracefully if provider is unavailable.

const provider = ($env.LLM_PROVIDER || 'claude').toLowerCase();
const prompt   = 'You are a senior threat intelligence analyst. Generate a concise executive-level Daily SOC Report based on the following data:\n\n## Dashboard Stats (Last 24h)\n' + JSON.stringify($('Fetch Dashboard Stats').item.json, null, 2) + '\n\n## Top Critical Alerts\n' + JSON.stringify($('Fetch Top Critical Alerts').item.json, null, 2) + '\n\n## Open Incidents\n' + JSON.stringify($('Fetch Open Incidents').item.json, null, 2) + '\n\nFormat the report with: 1. Executive Summary (3 sentences) 2. Key Threat Metrics 3. Top 3 Threats 4. MITRE ATT&CK Techniques 5. Recommended Actions. Be specific and under 500 words.';
const maxTok   = 2048;

let apiUrl, headers, body, modelKey;

if (provider === 'openai' || provider === 'gpt') {
  // ── OpenAI ──────────────────────────────────────────────────────────
  const model = $env.OPENAI_MODEL_ANALYSIS || $env.LLM_MODEL_PRIMARY || 'gpt-4o';
  apiUrl  = 'https://api.openai.com/v1/chat/completions';
  headers = {
    'Content-Type':  'application/json',
    'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
  };
  body = JSON.stringify({
    model,
    max_tokens: maxTok,
    messages: [{ role: 'user', content: prompt }],
  });
  modelKey = 'openai:' + model;

} else if (provider === 'gemini' || provider === 'google') {
  // ── Gemini ──────────────────────────────────────────────────────────
  const model = $env.GEMINI_MODEL_ANALYSIS || $env.LLM_MODEL_PRIMARY || 'gemini-1.5-pro';
  apiUrl  = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${$env.GOOGLE_API_KEY}`;
  headers = { 'Content-Type': 'application/json' };
  body = JSON.stringify({
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: maxTok },
  });
  modelKey = 'gemini:' + model;

} else {
  // ── Claude (default) ─────────────────────────────────────────────────
  const model = $env.LLM_MODEL_ANALYSIS || 'claude-sonnet-4-6';
  apiUrl  = 'https://api.anthropic.com/v1/messages';
  headers = {
    'Content-Type':      'application/json',
    'x-api-key':         $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
  };
  body = JSON.stringify({
    model,
    max_tokens: maxTok,
    messages: [{ role: 'user', content: prompt }],
  });
  modelKey = 'claude:' + model;
}

// Make the HTTP call
const resp = await $helpers.httpRequest({
  method:  'POST',
  url:     apiUrl,
  headers: headers,
  body:    body,
});

// ── Extract text from provider-specific response format ───────────────
let responseText = '';
if (provider === 'openai' || provider === 'gpt') {
  responseText = resp.choices?.[0]?.message?.content || '';
} else if (provider === 'gemini' || provider === 'google') {
  responseText = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
} else {
  responseText = resp.content?.[0]?.text || '';
}

return [{ json: { responseText, modelKey, provider } }];

const stats = $('Fetch Dashboard Stats').item.json;
const report = $('AI: Generate Daily Report (Multi-Provider)').item.json?.responseText || 'Report generation failed';
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const riskLevel = stats.critical_alerts_24h > 10 ? '🔴 HIGH RISK' 
  : stats.critical_alerts_24h > 3 ? '🟠 ELEVATED' 
  : '🟢 NORMAL';

return [{ json: { report, stats, date, riskLevel } }];

